mapper.select:
SELECT TO_CHAR(rv.CHECK_OUT_DATE, 'YYYY-MM') AS settlementMonth, NVL(SUM(o.REAL_TOTAL_AMOUNT), 0) AS gmv, NVL(SUM(o.COUPON_DISCOUNT), 0) AS couponDiscount, NVL(SUM(o.POINT_DISCOUNT), 0) AS pointUsed, NVL(SUM(ROUND(o.REAL_TOTAL_AMOUNT * p.COMMISSION_RATE / 100)), 0) AS commission, NVL(SUM(o.REAL_TOTAL_AMOUNT - ROUND(o.REAL_TOTAL_AMOUNT * p.COMMISSION_RATE / 100)), 0) AS partnerPayout, NVL(SUM(ROUND(o.REAL_TOTAL_AMOUNT * p.COMMISSION_RATE / 100)) - SUM(o.COUPON_DISCOUNT) - SUM(o.POINT_DISCOUNT), 0) AS netProfit, COUNT(DISTINCT p.PARTNER_ID) AS partnerCount, /* 해당 월 파트너 정산 상태 집계 */ CASE WHEN COUNT(DISTINCT p.PARTNER_ID) = COUNT(DISTINCT CASE WHEN ps.status = 'done' THEN p.PARTNER_ID END) THEN 'DONE' WHEN COUNT(DISTINCT CASE WHEN ps.status = 'done' THEN p.PARTNER_ID END) > 0 THEN 'PARTIAL' ELSE 'WAIT' END AS status, CASE WHEN COUNT(DISTINCT p.PARTNER_ID) = COUNT(DISTINCT CASE WHEN ps.status = 'done' THEN p.PARTNER_ID END) THEN 'badge-done' WHEN COUNT(DISTINCT CASE WHEN ps.status = 'done' THEN p.PARTNER_ID END) > 0 THEN 'badge-partial' ELSE 'badge-wait' END AS statusBadgeClass, CASE WHEN COUNT(DISTINCT p.PARTNER_ID) = COUNT(DISTINCT CASE WHEN ps.status = 'done' THEN p.PARTNER_ID END) THEN '완료' WHEN COUNT(DISTINCT CASE WHEN ps.status = 'done' THEN p.PARTNER_ID END) > 0 THEN '부분승인' ELSE '대기' END AS statusLabel FROM ORDERS o INNER JOIN ORDER_DETAIL od ON o.ORDER_ID = od.ORDER_ID INNER JOIN RESERVATION rv ON od.RESERVATION_ID = rv.RESERVATION_ID INNER JOIN ROOM rm ON rv.ROOM_ID = rm.ROOM_ID INNER JOIN PLACE pl ON rm.PLACE_ID = pl.PLACE_ID INNER JOIN PARTNER p ON pl.PARTNER_ID = p.PARTNER_ID LEFT JOIN PARTNER_SETTLEMENT ps ON ps.PARTNER_ID = p.PARTNER_ID AND ps.SETTLEMENT_MONTH = TO_CHAR(rv.CHECK_OUT_DATE, 'YYYY-MM') WHERE o.STATUS != 'CANCELED' AND TO_CHAR(rv.CHECK_OUT_DATE, 'YYYY') = TO_CHAR(#{year})
AND TO_CHAR(rv.CHECK_OUT_DATE, 'MM') = #{month}
GROUP BY TO_CHAR(rv.CHECK_OUT_DATE, 'YYYY-MM') ORDER BY TO_CHAR(rv.CHECK_OUT_DATE, 'YYYY-MM') DESC
